/**
 * Email notification handler — formats and sends email notifications
 * for order lifecycle events.
 *
 * Integrates with the existing NotificationService via the EventBus.
 * Subscribes to order events and dispatches formatted email notifications.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

/**
 * Maps order statuses to human-readable labels for email content.
 */
const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for email notifications.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send order confirmation email.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td><td>$${(item.quantity * item.unitPrice).toFixed(2)}</td></tr>`,
      )
      .join('\n');

    const itemList = event.order.items
      .map(
        (item) =>
          `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)} = $${(item.quantity * item.unitPrice).toFixed(2)}`,
      )
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Hi ${event.user.name},</p>
<p>Thank you for your order <strong>${event.order.id}</strong>!</p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th><th>Subtotal</th></tr>
${itemRows}
</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`;

    const textBody = `Order Confirmation

Hi ${event.user.name},

Thank you for your order ${event.order.id}!

Items:
${itemList}

Total: $${event.order.total.toFixed(2)}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Handle order status change — send status update email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const newLabel = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
    const prevLabel = STATUS_LABELS[event.previousStatus as OrderStatus] ?? event.previousStatus;
    const statusMessage = this.getStatusMessage(event.newStatus as OrderStatus, event.order.id);

    const htmlBody = `<h1>Order Status Update</h1>
<p>Your order <strong>${event.order.id}</strong> status has changed from <em>${prevLabel}</em> to <strong>${newLabel}</strong>.</p>
<p>${statusMessage}</p>`;

    const textBody = `Order Status Update

Your order ${event.order.id} status has changed from ${prevLabel} to ${newLabel}.

${statusMessage}`;

    this.sendEmail({
      to: event.order.userId,
      subject: `Order ${newLabel}: ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Get a friendly message for each status transition.
   */
  private getStatusMessage(status: OrderStatus, orderId: string): string {
    switch (status) {
      case 'confirmed':
        return `Your order ${orderId} has been confirmed and is being prepared.`;
      case 'shipped':
        return `Your order ${orderId} has been shipped and is on its way!`;
      case 'delivered':
        return `Your order ${orderId} has been delivered. Enjoy!`;
      case 'cancelled':
        return `Your order ${orderId} has been cancelled.`;
      default:
        return `Your order ${orderId} status has been updated.`;
    }
  }

  /**
   * Send an email (in-memory for this demo).
   * In production, this would integrate with an email provider (e.g., SES, SendGrid).
   */
  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: EmailMessage = {
      to: params.to,
      subject: params.subject,
      htmlBody: params.htmlBody,
      textBody: params.textBody,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get emails sent to a specific address.
   */
  getEmailsForRecipient(to: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === to);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

